#include <stdio.h>

int main(void) {
    int paid, cost;
    int change, dollars, cents;

    scanf("%d %d", &paid, &cost);

    change = paid - cost;
    dollars = change / 100;
    cents = change % 100;

    printf("%d %d\n", dollars, cents);
    return 0;
}

#include <stdio.h>

int main(void) {
    int a, b, c;
    int sum, average, remainder;

    scanf("%d %d %d", &a, &b, &c);

    sum = a + b + c;
    average = sum / 3;
    remainder = sum % 3;

    printf("%d %d\n", average, remainder);
    return 0;
}

#include <stdio.h>

int main(void) {
    int cm;
    int meters, rest;

    scanf("%d", &cm);

    meters = cm / 100;
    rest = cm % 100;

    printf("%d %d\n", meters, rest);
    return 0;
}

#include <stdio.h>

int main(void) {
    int score, bonus, penalty;
    int final_score;

    scanf("%d %d %d", &score, &bonus, &penalty);

    final_score = score + bonus - penalty;

    printf("%d\n", final_score);
    return 0;
}

#include <stdio.h>

int main(void) {
    int base, scale, adjust;
    int result;

    scanf("%d %d %d", &base, &scale, &adjust);

    result = base * scale - adjust;

    printf("%d\n", result);
    return 0;
}

#include <stdio.h>

int main(void) {
    int total_minutes;
