}

#include <stdio.h>

int main(void) {
    int price, tax_rate;
    int final_price;

    scanf("%d %d", &price, &tax_rate);

    final_price = price + (price * tax_rate) / 100 - 50;

    printf("%d\n", final_price);
    return 0;
}

#include <stdio.h>

int main(void) {
    int x, y, dx, dy;

    scanf("%d %d %d %d", &x, &y, &dx, &dy);

    x = x + dx;
    y = y + dy;

    printf("%d %d\n", x, y);
    return 0;
}

#include <stdio.h>

int main(void) {
    int items, capacity;
    int boxes, leftovers;

    scanf("%d %d", &items, &capacity);

    boxes = items / capacity;
    leftovers = items % capacity;

    printf("%d %d\n", boxes, leftovers);
    return 0;
}

#include <stdio.h>

int main(void) {
    int value, add, sub;

    scanf("%d %d %d", &value, &add, &sub);

    value = value + add;
    value = value - sub;

    printf("%d\n", value);
    return 0;
}
